<?php namespace App\Repositories;use App\Contracts\RepositoryInterface;use App\Exceptions\RepositoryException;use Illuminate\Database\Eloquent\Model;use Illuminate\Database\Eloquent\Builder;use Illuminate\Pagination\LengthAwarePaginator;use Illuminate\Support\Collection;use Illuminate\Support\Facades\DB;use Illuminate\Support\Facades\Schema;use Exception;class BaseRepository implements RepositoryInterface{    protected Model $model;    protected array $with = [];    protected array $orderBy = [];    protected ?int $schoolId = null;    protected string $schoolIdColumn = 'school_id';    protected bool $multiTenant = true;    public function __construct(Model $model)    {        $this->model = $model;    }    protected function query(): Builder    {        $query = $this->model->newQuery()->with($this->with);        if (!empty($this->orderBy)) {            foreach ($this->orderBy as $column => $direction) {                $query->orderBy($column, $direction);            }        }        if ($this->multiTenant && $this->schoolId) {            $query->where($this->schoolIdColumn, $this->schoolId);        }        return $query;    }    public function getAll(array $columns = ['*']): Collection    {        return $this->query()->get($columns);    }    public function getPaginated(int $perPage = 15, array $columns = ['*']): LengthAwarePaginator    {        return $this->query()->paginate($perPage, $columns);    }    public function getById($id, array $columns = ['*']): ?Model    {        return $this->query()->findOrFail($id, $columns);    }    public function create(array $data): Model    {        try {            DB::beginTransaction();            if ($this->multiTenant && $this->schoolId && !isset($data[$this->schoolIdColumn])) {                $data[$this->schoolIdColumn] = $this->schoolId;            }            $model = $this->model->newInstance();            $model->fill($data);            $model->save();            DB::commit();            return $model;        } catch (Exception $e) {            DB::rollBack();            throw new RepositoryException("Failed to create record: " . $e->getMessage(), 500, $e);        }    }    public function update($id, array $data): Model    {        try {            DB::beginTransaction();            $model = $this->getById($id);            $model->fill($data);            $model->save();            DB::commit();            return $model->fresh();        } catch (Exception $e) {            DB::rollBack();            throw new RepositoryException("Failed to update record with ID {$id}: " . $e->getMessage(), 500, $e);        }    }    public function delete($id): bool    {        try {            DB::beginTransaction();            $model = $this->getById($id);            $deleted = $model->delete();            DB::commit();            return $deleted;        } catch (Exception $e) {            DB::rollBack();            throw new RepositoryException("Failed to delete record with ID {$id}: " . $e->getMessage(), 500, $e);        }    }    public function findByField(string $field, $value, array $columns = ['*']): Collection    {        return $this->query()->where($field, $value)->get($columns);    }    public function findWhere(array $conditions, array $columns = ['*']): Collection    {        $query = $this->query();        foreach ($conditions as $field => $value) {            if (is_array($value)) {                $query->where($field, $value[0], $value[1]);            } else {                $query->where($field, $value);            }        }        return $query->get($columns);    }    public function count(array $conditions = []): int    {        if (empty($conditions)) {            return $this->query()->count();        }        $query = $this->query();        foreach ($conditions as $field => $value) {            if (is_array($value)) {                $query->where($field, $value[0], $value[1]);            } else {                $query->where($field, $value);            }        }        return $query->count();    }    public function pluck(string $value, string $key = null): Collection    {        return $this->query()->pluck($value, $key);    }    public function bulkDelete(array $ids): bool    {        try {            DB::beginTransaction();            $query = $this->model->newQuery()->whereIn('id', $ids);            if ($this->multiTenant && $this->schoolId) {                $query->where($this->schoolIdColumn, $this->schoolId);            }            $deleted = $query->delete();            DB::commit();            return $deleted > 0;        } catch (Exception $e) {            DB::rollBack();            throw new RepositoryException("Failed to bulk delete records: " . $e->getMessage(), 500, $e);        }    }    public function bulkInsert(array $data): bool    {        try {            if ($this->multiTenant && $this->schoolId) {                $data = array_map(function ($item) {                    if (!isset($item[$this->schoolIdColumn])) {                        $item[$this->schoolIdColumn] = $this->schoolId;                    }                    return $item;                }, $data);            }            return $this->model->newQuery()->insert($data);        } catch (Exception $e) {            throw new RepositoryException("Failed to bulk insert records: " . $e->getMessage(), 500, $e);        }    }    public function firstOrCreate(array $attributes, array $values = []): Model    {        try {            DB::beginTransaction();            if ($this->multiTenant && $this->schoolId && !isset($attributes[$this->schoolIdColumn])) {                $attributes[$this->schoolIdColumn] = $this->schoolId;            }            $model = $this->model->newQuery()->firstOrCreate($attributes, $values);            DB::commit();            return $model;        } catch (Exception $e) {            DB::rollBack();            throw new RepositoryException("Failed to firstOrCreate record: " . $e->getMessage(), 500, $e);        }    }    public function updateOrCreate(array $attributes, array $values = []): Model    {        try {            DB::beginTransaction();            if ($this->multiTenant && $this->schoolId && !isset($attributes[$this->schoolIdColumn])) {                $attributes[$this->schoolIdColumn] = $this->schoolId;            }            $model = $this->model->newQuery()->updateOrCreate($attributes, $values);            DB::commit();            return $model;        } catch (Exception $e) {            DB::rollBack();            throw new RepositoryException("Failed to updateOrCreate record: " . $e->getMessage(), 500, $e);        }    }    public function with(array $relations): static    {        $this->with = array_merge($this->with, $relations);        return $this;    }    public function orderBy(string $column, string $direction = 'asc'): static    {        $this->orderBy[$column] = $direction;        return $this;    }    public function setSchoolId(?int $schoolId): static    {        $this->schoolId = $schoolId;        return $this;    }    public function setMultiTenant(bool $enabled): static    {        $this->multiTenant = $enabled;        return $this;    }    public function getModel(): Model    {        return $this->model;    }    public function newInstance(): static    {        return new static($this->model->newInstance());    }    public function hasColumn(string $column): bool    {        return Schema::hasColumn($this->model->getTable(), $column);    }}